from pathlib import Path
import json,nbformat
ROOT=Path(__file__).resolve().parents[1]; NB=ROOT/"random_forest_classification_masterclass.ipynb"; HTML=ROOT/"random_forest_classification_masterclass.html"
nb=nbformat.read(NB,as_version=4); code=[c for c in nb.cells if c.cell_type=="code"]; md=[c for c in nb.cells if c.cell_type=="markdown"]; errors=[o for c in code for o in c.get("outputs",[]) if o.get("output_type")=="error"]; unexecuted=[c for c in code if c.get("execution_count") is None]; figs=sum("image/png" in o.get("data",{}) for c in code for o in c.get("outputs",[])); chapters=sum(c.source.lstrip().startswith("## ") for c in md); required=[ROOT/"README.md",ROOT/"environment.yaml",ROOT/"requirements-lock.txt",ROOT/"data"/"loan_default_teaching.csv",NB,HTML,ROOT/"model_card.json"]; missing=[str(p.relative_to(ROOT)) for p in required if not p.exists()]; report={"total_cells":len(nb.cells),"markdown_cells":len(md),"code_cells":len(code),"chapters":chapters,"unexecuted_code_cells":len(unexecuted),"error_outputs":len(errors),"embedded_png_figures":figs,"missing_required_files":missing,"minimum_code_cells":25,"minimum_figures":35,"minimum_chapters":28}; report["passes"]=not missing and not unexecuted and not errors and len(code)>=25 and figs>=35 and chapters>=28; (ROOT/"validation_report.json").write_text(json.dumps(report,indent=2)); print(json.dumps(report,indent=2)); raise SystemExit(0 if report["passes"] else 1)
